from langchain_core.runnables import RunnableLambda, RunnablePassthrough
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import StrOutputParser
from langchain_openai import ChatOpenAI

llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)

prompt = ChatPromptTemplate.from_template(
    """Answer the question using only the context below.

Context:
{context}

Question: {question}"""
)

def swap_windows(docs: list) -> str:
    """Replace each retrieved sentence with its window and format for prompt."""
    deduped = deduplicate_windows(docs)
    return "\n\n".join(
        f"[{i+1}] {doc.metadata['window']}"
        for i, doc in enumerate(deduped)
    )

rag_chain = (
    {
        "context": retriever | RunnableLambda(swap_windows),
        "question": RunnablePassthrough(),
    }
    | prompt
    | llm
    | StrOutputParser()
)

answer = rag_chain.invoke("explain how transformers handle variable-length sequences")
print(answer)
